import java.util.*;class Player{static int n,lx,rx,ly;static int[]sx=new int[30],sy=new int[30];static double tx;static double gy(double px){for(int i=0;i<n-1;i++)if(px>=sx[i]&&(px<sx[i+1]||i==n-2))return sy[i]+(double)(sy[i+1]-sy[i])*(px-sx[i])/(sx[i+1]-sx[i]);return sy[n-1];}public static void main(String[]a){var s=new Scanner(System.in);n=s.nextInt();for(int i=0;i<n;i++){sx[i]=s.nextInt();sy[i]=s.nextInt();}for(int i=0;i<n-1;i++)if(sy[i]==sy[i+1]&&sx[i+1]-sx[i]>=1000){lx=sx[i];rx=sx[i+1];ly=sy[i];break;}tx=(lx+rx)/2.0;for(;;){int X=s.nextInt(),Y=s.nextInt(),hs=s.nextInt(),vs=s.nextInt(),fu=s.nextInt(),ro=s.nextInt(),pw=s.nextInt();double dg=Y-gy(X),df=Y-ly;boolean over=X>=lx&&X<=rx;int ah=Math.abs(hs),blocked=0;if(!over){int step=X<lx?50:-50;double cx=X;for(int j=0;j<200;j++){cx+=step;if(cx<0||cx>6999)break;if((step>0&&cx>rx)||(step<0&&cx<lx))break;if(gy(cx)>Y-100){blocked=1;break;}}}int tr=0,tp=4;if(dg<100&&vs<-30){tr=0;tp=4;}else if(blocked==1&&!over){tp=vs<10?4:3;tr=X<lx?-20:20;}else if(!over){if(X<lx){if(hs<0)tr=30;else if(hs>80)tr=60;else if(hs>40)tr=30;else tr=-30-Math.min(30,Math.max(0,(lx-X)/50));}else{if(hs>0)tr=-30;else if(hs<-80)tr=-60;else if(hs<-40)tr=-30;else tr=30+Math.min(30,Math.max(0,(X-rx)/50));}tp=4;}else if(df<400&&ah<=25){tr=0;tp=vs<-38?4:vs<-25?3:vs<-10?2:vs>5?0:1;}else if(over){tr=ah>20?(hs>0?Math.min(45,hs):Math.max(-45,hs)):(X<tx-100?-10:X>tx+100?10:0);tp=vs<-35?4:tr!=0?4:vs>-15?2:3;}else{tr=ah>5?(hs>0?15:-15):0;tp=vs<-30?4:3;}int dr=Math.max(-90,Math.min(90,tr));dr=Math.max(ro-15,Math.min(ro+15,dr));int dp=Math.max(0,Math.min(4,tp));dp=Math.max(pw-1,Math.min(pw+1,dp));System.out.println(dr+" "+dp);System.out.flush();}}}
